The cumulative frequency diagram shows information about the time taken, $t$ seconds, for a group of girls to each solve a maths problem.

	\begin{InsertScreenShot}
	% \relincludegraphics{Figures/Q02-CumulativeFrequencyDiagram.png}
	% [Image: Cumulative frequency diagram with Time (seconds) on x-axis (0-100) and Cumulative frequency on y-axis (0-80)]
	\end{InsertScreenShot}

	\begin{parts}
	\item Use the cumulative frequency diagram to find an estimate for

	\begin{subparts}
	\item the median,

	\AnswerLine[][s]
	\Marks{1}

	\item the interquartile range,

	\AnswerLine[][s]
	\Marks{2}

	\item the 20th percentile,

	\AnswerLine[][s]
	\Marks{1}

	\item the number of girls who took more than 66 seconds to solve the problem.

	\AnswerLine[][]
	\Marks{2}
	\end{subparts}

	\item
	\begin{subparts}
	\item Use the cumulative frequency diagram to complete the frequency table.

	\begin{center}
	\begin{tabularx}{0.9\textwidth}{|l|C|C|C|C|C|}
	\hline
	Time ($t$ seconds) & $0 < t \leqslant 20$ & $20 < t \leqslant 40$ & $40 < t \leqslant 60$ & $60 < t \leqslant 80$ & $80 < t \leqslant 100$ \\
	\hline
	Frequency & 6 & & & & 4 \\
	\hline
	\end{tabularx}
	\end{center}
	\Marks{2}

	\item Calculate an estimate of the mean time.

	\AnswerLine[][s]
	\Marks{4}
	\end{subparts}

	\item A group of boys solved the same problem.\\
	The boys had a median time of 60 seconds, a lower quartile of 46 seconds and an upper quartile of 66 seconds.

	\begin{subparts}
	\item Write down the percentage of boys with a time of 66 seconds or less.

	\AnswerLine[][\%]
	\Marks{1}

	\item Howard says

	\noindent \hspace{1cm} The boys' times vary more than the girls' times.

	Explain why Howard is incorrect.

	\answerlines[2]
	\Marks{2}
	\end{subparts}

	\end{parts}

